const Q_PHYSICS_2006=[{"id": "objective>Physics>2006>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When the base current of a common-emitter transistor is kept at zero, it operates in the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">active-on region </div>", "<div style=\"font-family:Cambria;font-size:17px;\">breakdown region</div>", "<div style=\"font-family:Cambria;font-size:17px;\">saturation region </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cut-off region</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A common-emitter transistor with zero base current operates in the cut-off region. In this region, both the emitter-base junction and the collector-base junction are reverse biased. This means that there is no current flowing through the transistor, effectively 'cutting off' the transistor from the circuit.</div>", "topic": "INTRODUCTORY ELECTRONICS : TRANSISTORS"}, {"id": "objective>Physics>2006>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the properties of gamma rays is that they are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">negatively charged</div>", "<div style=\"font-family:Cambria;font-size:17px;\">massive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">neutral</div>", "<div style=\"font-family:Cambria;font-size:17px;\">positively charged</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gamma rays are a type of electromagnetic radiation, like light or radio waves, but with much higher energy. As such, they are not charged and have no mass, making them neutral. They can pass through many materials without being affected, which is why they are often used in medical imaging and cancer treatment.</div>", "topic": "ELEMENTARY MODERN PHYSICS : ALPHA, BETA AND GAMMA RAYS"}, {"id": "objective>Physics>2006>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The theory of electronic conduction in solids, which satisfactorily explains the properties of conductors, insulators and semiconductors is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">particle theory</div>", "<div style=\"font-family:Cambria;font-size:17px;\">band theory</div>", "<div style=\"font-family:Cambria;font-size:17px;\">group theory</div>", "<div style=\"font-family:Cambria;font-size:17px;\">string theory</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The theory of electronic conduction in solids, which satisfactorily explains the properties of conductors, insulators and semi-conductors is the band theory.</div>", "topic": "INTRODUCTORY ELECTRONICS : METALS, SEMICONDUCTORS AND INSULATORS"}, {"id": "objective>Physics>2006>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A radioactive element has a half life of 4 days. The fraction that has decayed in 16 days is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3/4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1/16</div>", "<div style=\"font-family:Cambria;font-size:17px;\">15/16</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1/4</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1/2</span> (half - life) = 4 days  <br/> Let the original size be x <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">Fraction decay</td><td style=\"border:1px solid black;text-align:center;\">Fraction left</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Day 1 - 4 <br/> Day 5 - 8 <br/> Day 9 - 12 <br/> Day 13 - 16</td><td style=\"border:1px solid black;text-align:center;\">x/2 <br/> x/4 <br/> x/8 <br/> x/16</td><td style=\"border:1px solid black;text-align:center;\">x/2 <br/> x/4 <br/> x/8 <br/> x/16</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Total</td><td style=\"text-align:center;\">fraction</td><td style=\"text-align:center;\">decayed</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">x<hr size=\"1\" />2</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">x<hr size=\"1\" />4</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">x<hr size=\"1\" />8</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">x<hr size=\"1\" />16</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">(8 + 4 + 2 + 1)x<hr size=\"1\" />16</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">15x<hr size=\"1\" />16</td></tr></table></div></div>", "topic": "ELEMENTARY MODERN PHYSICS : HALF-LIFE AND DECAY CONSTANT"}, {"id": "objective>Physics>2006>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A certain manufacturer wishes to make an n-type semi-conductor. Which materials would he select for dopping?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Arsenic and antimony</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Aluminium and indium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Boron and antimony</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Helium and boron</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In semiconductor physics, n-type semiconductors are created by doping an intrinsic semiconductor with an electron donor element during manufacture. The phrase 'n-type' comes from the negative charge of the electron. In this case, both arsenic and antimony are commonly used as dopants to produce n-type semiconductors.</div>", "topic": "INTRODUCTORY ELECTRONICS : N-TYPE AND P-TYPE SEMI-CONDUCTORS"}, {"id": "objective>Physics>2006>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following diagrams represents correctly an n-p-n transistor?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The diagram that represents correctly an n-p-n transistor is: <br/> <img src=\"2006/2TWDHD.png\" style=\"position:relative;max-width:100%;\"/></div>", "topic": "INTRODUCTORY ELECTRONICS : TRANSISTORS"}, {"id": "objective>Physics>2006>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. The number of neutrons released exceeds the number that caused the fission. <br/> II. There is loss of mass  <br/>  III. Energy is produced  <br/> IV. Smaller nuclei merge to form larger nuclei  <br/> Which of the statements above are correct about nuclear fission?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I, II and IV only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, III and IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II, III and IV only </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nuclear fission is a reaction in which the nucleus of an atom splits into two or more smaller nuclei. The statements I, II and III are correct about nuclear fission. I: More neutrons are indeed released than were involved in initiating the fission. II: There is a loss of mass because the mass of the products of fission is less than the mass of the original nucleus. This 'missing' mass has been converted into energy, according to Einstein's equation E=mc^2. III: Energy is produced in the form of kinetic energy of the fission products and emitted neutrons, and also as electromagnetic energy. IV: is incorrect because in nuclear fission, a larger nucleus splits into smaller nuclei, it does not merge to form larger nuclei.</div>", "topic": "ELEMENTARY MODERN PHYSICS : FUSION AND FISSION"}, {"id": "objective>Physics>2006>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The energy associated with the emitted photon when a mercury atom changes from one state to another is 3.3eV. Calculate the frequency of the photon. <br/>  <br/>  [e= 1.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>C; h = 6.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-34</span>Js]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">14</span>Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.1 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">52</span>Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-15</span>Hz.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-53</span>Hz </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameter given <br/> Energy, E = 3.3 eV <br/> N.B: e = 1.6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>C <br/> E = 3.3 × 1.6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span> <br/> E = 5.28 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>J <br/> Recall: E = hf <br/> 5.28 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span> = 6.6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-34</span> × f  <br/> f = 0.8 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">15</span> <br/> f = 8 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">14</span>Hz</div>", "topic": "ELEMENTARY MODERN PHYSICS : THERMIONIC AND PHOTOELECTRIC EMISSIONS"}, {"id": "objective>Physics>2006>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A p-n junction diode is used as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a rectifier in an d.c circuit </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an amplifier in an a.c circuit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a rectifier in an a.c circuit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an amplifier in a d.c circuit</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A p-n junction diode is commonly used as a rectifier in an alternating current (a.c) circuit. A rectifier is an electrical device that converts alternating current, which periodically reverses direction, to direct current (d.c.), which flows in only one direction. The process is known as rectification.</div>", "topic": "INTRODUCTORY ELECTRONICS : DIODES"}, {"id": "objective>Physics>2006>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The battery connection that permits current to flow across a p-n junction is called </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">amplification</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rectification</div>", "<div style=\"font-family:Cambria;font-size:17px;\">forward biased</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reverse biased</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The battery connection that permits current to flow across a p-n junction is called forward bias. In a forward bias, the p-side of the diode is connected to the positive terminal of the battery and the n-side is connected to the negative terminal. This allows current to flow from the p-side to the n-side. Therefore, the correct answer is option 3.</div>", "topic": "INTRODUCTORY ELECTRONICS : DIODES"}, {"id": "objective>Physics>2006>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The process through which free electrons leave the surface of hot metals is known as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">thermionic emission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">photo emission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">photon emission </div>", "<div style=\"font-family:Cambria;font-size:17px;\">electron emission</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The process through which free electrons leave the surface of hot metals is known as thermionic emission. This is a phenomenon in which electrons are given enough thermal energy to overcome the work function of the metal and escape from the surface. This is different from photo emission where electrons are ejected due to the absorption of light energy, and photon emission which is the release of photons from an atom or molecule, and electron emission which is a general term for any process that results in the ejection of an electron from a system.</div>", "topic": "ELEMENTARY MODERN PHYSICS : THERMIONIC EMISSIONS"}, {"id": "objective>Physics>2006>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A mirror of weight 75N is hung by a cord from a hook on the wall. If the chord makes an angle of 30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> with the horizontal, the tension in the cord is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">150N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1500N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">250N</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Diagrammatically, <br/> <img src=\"2006/img12.png\" style=\"position:relative;max-width:100%;\"/> <br/> Tsin30° = 75 <br/> T(0.5) = 75 <br/> T = 150N </div>", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES"}, {"id": "objective>Physics>2006>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The motion of smoke particles from a chimney is typical of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">oscillatory motion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rotational motion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">circular motion </div>", "<div style=\"font-family:Cambria;font-size:17px;\">random motion </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The motion of smoke particles from a chimney is typical of random motion. Random motion is the zig zag or haphazard change in position of particles; it is a form of motion that has no preferred orientation, i.e it is scattered.</div>", "topic": "MOTION: TYPES OF MOTION"}, {"id": "objective>Physics>2006>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The component of vector X along the direction of vector Y is zero when </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">X is at an angle of 45<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> to Y</div>", "<div style=\"font-family:Cambria;font-size:17px;\">X and Y are in opposite directions to each other </div>", "<div style=\"font-family:Cambria;font-size:17px;\">X and Y are parallel to each other </div>", "<div style=\"font-family:Cambria;font-size:17px;\">X is perpendicular to Y</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The component of a vector along the direction of another vector is found using the dot product. <br/> When two vectors are perpendicular to each other, the dot product is zero. <br/> So, if X is perpendicular to Y, the component of X along the direction of Y is zero.</div>", "topic": "SCALARS AND VECTORS"}, {"id": "objective>Physics>2006>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. Work done by load is always less than the work done by effort  <br/> II. All machines are made of levers, pulleys, screws and gear wheels  <br/>  III. A fishing rod is a machine  <br/>  IV. Effort is always larger than load.  <br/>  Which of the statements above about machines are true?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">III and IV </div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a machine  <br/> * workdone by load is always less than workdone by effort  <br/> * A fishing rod is a machine i.e a lever  <br/> I and III are true.</div>", "topic": "SIMPLE MACHINES"}, {"id": "objective>Physics>2006>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An engine of a car of power 80kW moves on a rough road with a velocity  of 32ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. The force required to bring it to rest is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.50 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.50 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.56 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.80 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>N</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Power, P = 80kW = 80,000 W <br/> Velocity, V = 32ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> Force, F = Unknown <br/> Recall: <br/> P = F × V <br/> 80,000 = F × 32 <br/> F = 2500N</div>", "topic": "WORK, ENERGY AND POWER: POWER"}, {"id": "objective>Physics>2006>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the radius of the earth is 6.4 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>m, the escape velocity of a satellite from the earth is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8.00 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.00 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.13 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.27 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Radius of the earth, Re = 6.4 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>m <br/> Escape velocity, Ve = Unknown <br/> Acceleration due to gravity, g = 10.0ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> <br/> Recall: <br/> V = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">2gRe&nbsp;</span> <br/> V = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">20 × 6.4 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>&nbsp;</span> <br/> V = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">128 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>&nbsp;</span> <br/> V = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">2&nbsp;</span> × 8 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> V = 11.2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> V = 1.12 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span> ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "topic": "GRAVITATIONAL FIELD : ESCAPE VELOCITY"}, {"id": "objective>Physics>2006>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In an experiment to determine terminal velocity, as the pressure increases, the viscosity of a liquid </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increases then decreases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">remains constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increases </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Viscosity is a measure of a fluid's resistance to flow. It describes the internal friction of a moving fluid. A fluid with large viscosity resists motion because its molecular makeup gives it a lot of internal friction. A fluid with low viscosity flows easily because its molecular makeup results in very little friction when it is in motion. Viscosity is independent of pressure, so it remains constant as pressure increases.</div>", "topic": "FRICTION : VISCOSITY AND TERMINAL VELOCITY"}, {"id": "objective>Physics>2006>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A shooter wants to fire a bullet in such a way that its horizontal range is equal to three times its maximum height. At what angle should he fire the bullet to achieve this?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">53<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">68<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">45<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> R = 3Hm <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">u<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>sin2θ<hr size=\"1\" />g</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3</td><td style=\"text-align:center;\">(</td><td style=\"text-align:center;\">u<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>sin<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>θ<hr size=\"1\" />2g</td><td style=\"text-align:center;\">)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">sin2θ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3sin<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>θ<hr size=\"1\" />2</td></tr></table></div> <br/> Recall: sin2θ = 2sinθcosθ <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">2sinθcosθ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3sin<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>θ<hr size=\"1\" />2</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">2cosθ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3sinθ<hr size=\"1\" />2</td></tr></table></div> <br/> 4cosθ = 3sinθ <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">4<hr size=\"1\" />3</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">sinθ<hr size=\"1\" />cosθ</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">tanθ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4<hr size=\"1\" />3</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">θ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">tan<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>(</td><td style=\"text-align:center;\">4<hr size=\"1\" />3</td><td style=\"text-align:center;\">)</td></tr></table></div> <br/> θ = 53° <br/> </div>", "topic": "MOTION: PROJECTILES"}, {"id": "objective>Physics>2006>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The correct unit of energy density is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The current unit of energy density is kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall:</td><td style=\"text-align:center;\">Energy</td><td style=\"text-align:center;\">density</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Energy<hr size=\"1\" />Volume</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Force × distance<hr size=\"1\" />Area × Length</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">MLT<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> × L<hr size=\"1\" />L<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> × L</td></tr></table></div> <br/> ML<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>T<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> is the dimension of energy density = kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>S<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "topic": "MEASUREMENTS AND UNITS : DIMENSIONS"}, {"id": "objective>Physics>2006>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The production and type of charge of a body can only be accounted for by the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">equilibrium in protons and neutrons </div>", "<div style=\"font-family:Cambria;font-size:17px;\">deficiency or surplus of electrons</div>", "<div style=\"font-family:Cambria;font-size:17px;\">deficiency or surplus of protons </div>", "<div style=\"font-family:Cambria;font-size:17px;\">deficiency or surplus of neutrons</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The charge a possesses depends on whether there is Surplus electrons (-ve) or deficiecy in the number of electrons (+ve).</div>", "topic": "ELECTROSTATICS"}, {"id": "objective>Physics>2006>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The electrolyte in the Nickel-iron (Nife) accumulator is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ammonium chloride solution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dilute tetraoxosulphate(VI) acid </div>", "<div style=\"font-family:Cambria;font-size:17px;\">copper tetraoxosulphate(VI) solution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">potassium hydroxide solution</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The electrolyte in a Nickel-iron (NiFe) accumulator, also known as a NiFe battery, is potassium hydroxide solution. An electrolyte is a substance that produces an electrically conducting solution when dissolved in a polar solvent. In this case, potassium hydroxide (KOH) is the electrolyte.</div>", "topic": "ELECTRIC CELLS"}, {"id": "objective>Physics>2006>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main purpose of the transformer in an a.c radio set is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase power to the radio</div>", "<div style=\"font-family:Cambria;font-size:17px;\">convert energy from a.c to d.c</div>", "<div style=\"font-family:Cambria;font-size:17px;\">step down the voltage </div>", "<div style=\"font-family:Cambria;font-size:17px;\">step up the voltage </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The main purpose of the transformer in an a.c radio set is to step down the voltage. A transformer is a device that increases or decreases the voltage of an alternating current. In a radio set, the transformer is used to reduce the voltage from the power source to a level suitable for the sensitive electronic components in the radio.</div>", "topic": "ELECTROMAGNETIC INDUCTION : TRANSFORMERS"}, {"id": "objective>Physics>2006>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When an a.c voltage is applied to a capacitor, no power is consumed because the current</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">and voltage are 180<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> out of phase</div>", "<div style=\"font-family:Cambria;font-size:17px;\">and voltage are in phase</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lags behind the voltage by 90<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">leads the voltage by 90<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When an a.c voltage is applied to a capacitor no power is consumed because the current leads the voltage by 90°</div>", "topic": "SIMPLE A. C. CIRCUITS : CAPACITOR - CAPACITIVE REACTANCE"}, {"id": "objective>Physics>2006>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An electric heater with a p.d. of 240V connected across its terminals has a total resistance of 960ohms. Find the power rating of the heater.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4.00W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.25W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">60.00W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">38.40W</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Potential difference, V = 240V <br/> Resistance (Load), R = 960Ω <br/> Power, P = Unknown <br/> Recall: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />R</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">240×240<hr size=\"1\" />960</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">60W</td></tr></table></div></div>", "topic": "ELECTRICAL ENERGY AND POWER"}, {"id": "objective>Physics>2006>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An ammeter of resistance 5ohms has a full-scale deflection when a current of 50mA flows in it. The value of the resistor required to adapt it to measure a current of 5A is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">19.80ohms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.00ohms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.05ohms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.25ohms</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span>R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span> = IR <br/> 50 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> × 5 = 5 × R <br/> R = 5 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> = 0.05Ω</div>", "topic": "MAGNETIC FIELD : CONVERSION OF GALVANOMETERS TO AMMETERS AND VOLTMETER"}, {"id": "objective>Physics>2006>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a certain a.c supply is connected to a lamp, it lights with the same brightness as it does with a 12V d.c battery. The r.m.s value of the a.c supply is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8.5V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">17.0V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.5V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12.0V</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Since it has the same brightness, it shows that the rms value of AC voltage is equal to the DC voltage which is 12v due to the same heat dissipation power</div>", "topic": "SIMPLE A. C. CIRCUITS"}, {"id": "objective>Physics>2006>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">During electrolysis, 2.0g of a metal is deposited using a current of 0.5A in 3 hours. The mass of the same metal which can be deposited using a current of 1.5A in 1 hour is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.0g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.5g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.0g</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Mass, m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 2.0g (initial) <br/> Current, I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 0.05A (Initial) <br/> Time, t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 3 hrs (Initial) <br/> Mass, m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = Unknown (final) <br/> Current, I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 1.5A (final) <br/> Time, t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 1hr (final) <br/> Recall: Faraday's First Law of Electrolysis <br/> m αQ <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div> <br/> Recall: Q = It <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">∴</td><td style=\"text-align:center;\">2<hr size=\"1\" />0.05 × 3</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />1 × 1.5</td></tr></table></div> <br/> m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 2/0.1 = 20g</div>", "topic": "CURRENT ELECTRICITY: ELECTROLYSIS"}, {"id": "objective>Physics>2006>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the capacitance of a capacitor is C = εA/d, which of the following parameters is varied when a variable capacitor is used for tuning radio sets?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Area and distance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Constant (ε) only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Constant (ε) and area </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Distance only </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The capacitance (C) of a capacitor is given by the formula C = εA/d, where ε is the permittivity of the dielectric material, A is the area of one of the plates, and d is the distance between the plates. When tuning a radio, the variable capacitor is used to change the resonant frequency of the LC circuit, which is done by varying the capacitance. This is achieved by changing the distance (d) between the plates of the capacitor, while the area of the plates (A) and the permittivity of the dielectric material (ε) remain constant.</div>", "topic": "CAPACITORS : CAPACITANCE OF A CAPACITORS"}, {"id": "objective>Physics>2006>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following diagrams represents the magnetic field of two isolated unlike poles?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">NOTE: Magnetic lines of force points outward from the north pole (N) and goes toward the south pole, like what we have in. <br/> <img src=\"2006/ehy0630d.png\" style=\"position:relative;max-width:100%;\"/></div>", "topic": "MAGNETS AND MAGNETIC FIELDS"}, {"id": "objective>Physics>2006>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A cell of internal resistance r is connected to an external resistor R. The condition for maximum power transfer is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">R < r</div>", "<div style=\"font-family:Cambria;font-size:17px;\">R = 2r</div>", "<div style=\"font-family:Cambria;font-size:17px;\">R = r</div>", "<div style=\"font-family:Cambria;font-size:17px;\">R > r</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The condition for maximum power transfer from a source with a fixed internal resistance to a load (like a resistor) is when the resistance of the load matches the internal resistance of the source. This is known as the Maximum Power Transfer Theorem. Therefore, the correct answer is R = r.</div>", "topic": "ELECTRIC CELLS"}, {"id": "objective>Physics>2006>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The capacitance of a parallel-plate capacitor when in air is 3μf and in the presence of a dielectric material 6μf. The dielectric constant is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">18</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Capacitance in air, C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">a</span> = 3μF <br/> Capacitance in the presence of dielectric, C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span> = 6μF <br/> Dielectric constant, ε = unknown <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">ε<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">r</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">ε<hr size=\"1\" />ε<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">ε</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span><hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">a</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6μF<hr size=\"1\" />3μF</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2.0</td></tr></table></div></div>", "topic": "CAPACITORS : CAPACITANCE OF A CAPACITORS"}, {"id": "objective>Physics>2006>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A person can focus objects when they lie beyond 75cm from his eyes. The focal length of the lens required to reduce his least distance of distinct vision to 25cm is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">25.00cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">37.50cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">75.00cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">18.75cm</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Object distance, U = -75cm <br/> The required image distance, V = 25cm <br/> Focal length, f = unknown <br/> To make the person see the object clearly at 25cm, the image will be formed on the same side of the lens at 75cm.  <br/> When the image is viewed from the same side of the lens, it will be virtual which means the image distance will be negative. <br/>  <br/> u= 25cm, v=-75cm <br/>  <br/> 1/f= 1/u + 1/v <br/> 1/f= 1/25 + (-1/75) <br/> 1/f= 2/75 <br/> F=37.50cm</div>", "topic": "OPTICAL INSTRUMENTS : NEAR AND FAR POINTS"}, {"id": "objective>Physics>2006>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The frequency of the wave in the diagram above is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.05Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.17Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.57Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.25Hz</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It takes 4 seconds for 1 oscillation, according to the phase diagram given <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">∴</td><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">n<hr size=\"1\" />t</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />4</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.25Hz</td></tr></table></div></div>", "topic": "WAVES : PRODUCTION AND PROPAGATION"}, {"id": "objective>Physics>2006>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An object placed 10cm from a concave mirror of focal length 5cm would have its image</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">at infinity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10cm from the focus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">at the centre of curvature </div>", "<div style=\"font-family:Cambria;font-size:17px;\">at the radius of curvature</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Object distance, U = 10cm <br/> Focal length, f = 5cm <br/> N.B: U = 2f <br/> ∴ the image is at the centre of curvature.</div>", "topic": "REFLECTION OF LIGHT AT PLANE AND CURVED SURFACES : FORMATION OF IMAGES BY PLANE, CONCAVE AND CONVEX MIRRORS AND RAY DIAGRAMS"}, {"id": "objective>Physics>2006>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A progressive wave equation is represented by y = <em>a</em>sin(150πt - πx/4). If the phase difference of a progressive wave is 45<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>, the value of <em>x</em> in the equation is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1cm</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">y</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Asin(150πt</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">πx<hr size=\"1\" />4</td><td style=\"text-align:center;\">)</td></tr></table></div> <br/> ∅ = 45° <br/> N.B: ∅ = kx <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">∅</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">πx<hr size=\"1\" />4</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">45°</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">πx<hr size=\"1\" />4</td></tr></table></div> <br/> 180° = πx <br/> N.B: π = 180° <br/> 180° = 180°(x) <br/> x = 1.0cm</div>", "topic": "WAVES : PRODUCTION AND PROPAGATION"}, {"id": "objective>Physics>2006>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Non-luminous objects can be seen because they </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">are polished </div>", "<div style=\"font-family:Cambria;font-size:17px;\">are near</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reflect light </div>", "<div style=\"font-family:Cambria;font-size:17px;\">emit light</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Non-luminous objects do not emit their own light. They can be seen because they reflect light that falls on them from other sources. This reflected light reaches our eyes, enabling us to see the object.</div>", "topic": "LIGHT ENERGY : SOURCE OF LIGHT"}, {"id": "objective>Physics>2006>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A submarine is observed to rise from a real depth of 80m to 60m in water. Calculate the change in apparent depth. [Refractive index of water = 4/3]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">60m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">15m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">80m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">45m</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Real depth, r = 80m <br/> apparent depth, a = 60m <br/>  Refractive index (n) = real dept/apparent depth <br/> For 80m real depth : 4/32 = 80/apparent depth <br/> Apparent depth = 80/4 x 3 <br/>  = 60m <br/> From 60m real depth : 4*3 x 60/apparent depth <br/> App.depth = 60/15 x 3 = 45m <br/> Change in app.dept = 60-45 <br/>  = 15m</div>", "topic": "REFRACTION OF LIGHT THROUGH : PLANE AND CURVED SURFACE"}, {"id": "objective>Physics>2006>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The wavelength of the first overtone of a note in a closed pipe of length 33cm is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">44cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">33cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">22cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">17cm</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"2006/39.png\" style=\"position:relative;max-width:100%;\"/> <br/> {Fundamental overtone} <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">λ<hr size=\"1\" />4</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">l</td></tr></table></div> <br/> λ = 4l <br/>  <img src=\"2006/399.png\" style=\"position:relative;max-width:100%;\"/> {1st Overtone} <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">λ<hr size=\"1\" />4</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">λ<hr size=\"1\" />4</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">λ<hr size=\"1\" />4</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">L</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">3λ<hr size=\"1\" />4</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">L</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">λ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4L<hr size=\"1\" />3</td><td style=\"text-align:center;\">(for</td><td style=\"text-align:center;\">first</td><td style=\"text-align:center;\">overtone)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">λ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4(33)<hr size=\"1\" />3</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">44cm</td></tr></table></div> <br/> </div>", "topic": "CHARACTERISTICS OF SOUND WAVES : FREQUENCY OF A NOTE EMITTED BY AIR COLUMNS"}, {"id": "objective>Physics>2006>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/> The diagram above represents the stress-strain graph for a typical metal rod. What does <strong>X</strong> represent?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Yield point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Breaking point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Elastic limit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Proportional limit</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Elastic deformation is when a material returns to its original shape after a load is removed. The yield point is where it starts to deform permanently. The breaking point is when it fails under stress. So, X represents the maximum load a material can handle before it breaks. This is important for designing structures to ensure they can withstand expected loads.</div>", "topic": "ELASTICITY"}, {"id": "objective>Physics>2006>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the relative density of gold is 19.2, the volume of 2.4kg of gold is ...... <br/> [Density of water = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.92 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.61 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.00 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.25 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Relative Density, R.D = 19.2 = 19.2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> <br/> Volume, V = unknown <br/> Mass, m = 2.4kg <br/> Recall: <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">D</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">m<hr size=\"1\" />v</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">v</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">m<hr size=\"1\" />D</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">v</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2.4<hr size=\"1\" />19.2×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />8×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.125</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1.25</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></td></tr></table></div></div>", "topic": "LIQUIDS AT REST : RELATIVE DENSITY"}, {"id": "objective>Physics>2006>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The thermos flask is designed to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">prevent heat gain by conduction, convection and radiation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prevent heat loss by conduction, convection and radiation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prevent heat loss or gain by conduction, convection and radiation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">store hot tea or water</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The thermos flask is designed to keep the temperature of its content constant, i.e to prevent heat loss or gain by conduction, convection and radiation.</div>", "topic": "HEAT TRANSFER : THERMOS FLASK"}, {"id": "objective>Physics>2006>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An immersion heater rated 2.0A, 240V is used to boil water from temperature 52<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C to 100<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C. If the mass of the water is 2.5kg, determine the time taken to boil the water.  <br/>  <br/> [SHC of water, c = 4.2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>k<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.05 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.05 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.05 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.05 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>s</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Current, I = 2.0A <br/> Voltage, V = 240V <br/> Initial temperature, θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 52°C <br/> Final temperature, θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 100°C <br/> Mass of water, M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">w</span> = 2.5kg <br/> SHC of water, c = 4.2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>k<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> Note that electrical energy (IVt) has been converted into thermal energy (mcΔθ) <br/> 2 × 240 × t = 2.5 × 4.2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> × 50 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">t</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10.5 × 48 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span><hr size=\"1\" />2 × 240</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">t</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10.5 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span><hr size=\"1\" />2 × 5</td></tr></table></div> <br/> t = 10.5 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> t = 1.05 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>s</div>", "topic": "QUANTITY OF HEAT : HEAT CAPACITY AND SPECIFIC HEAT CAPACITY"}, {"id": "objective>Physics>2006>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is likely to happen if the glass of a thermometer expands more upon heating than the liquid inside?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The glass will shrink</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The liquid will go down in the stem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The liquid will rise up in the stem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The glass will break</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If the glass of a thermometer expands more upon heating than the liquid inside, the volume of the glass bulb will increase more than the volume of the liquid. This will create more space for the liquid, causing it to go down in the stem. Therefore, the correct option is 'The liquid will go down in the stem'.</div>", "topic": "TEMPERATURE AND ITS MEASUREMENT"}, {"id": "objective>Physics>2006>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A drop of petrol makes a finger colder than a drop of water would because </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">petrol takes its latent heat of fusion from the finger</div>", "<div style=\"font-family:Cambria;font-size:17px;\">petrol takes its latent heat of vaporization from the finger</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water has higher surface tension than petrol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water is more viscous than petrol</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a drop of petrol evaporates, it takes heat from its surroundings, in this case, the finger, to provide the latent heat of vaporization. This heat transfer makes the finger feel colder. Therefore, the correct option is 'petrol takes its latent heat of vaporization from the finger'.</div>", "topic": "CHANGE OF STATE : SPECIFIC LATENT HEATS OF VAPORIZATION"}, {"id": "objective>Physics>2006>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A uniform solid cube material 10cm on each side of mass 700g is submerged in water. Which of the following best describes the behaviour of the cube in water?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The cube will rest at an equilibrium position in water </div>", "<div style=\"font-family:Cambria;font-size:17px;\">The cube will melt after a period of time</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The cube will sink in water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The cube will float </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A uniform cube will have equal sides  <br/>  = 10 x 10 x 10 <br/>  = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> = 1000cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> Mass = 700g <br/> Recall,  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">density</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">mass<hr size=\"1\" />volume</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">700<hr size=\"1\" />1000</td></tr></table></div> <br/>  = 0.7gcm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> <br/> Density of water = 1 gcm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> <br/> Since the density of the cube is less than the density of water, the cube will float on the water.</div>", "topic": "LIQUIDS AT REST : ARCHIMEDE’S PRINCIPLE"}, {"id": "objective>Physics>2006>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a gas experiment, if the volume of the gas is plotted against the reciprocal of the pressure, the unit of the slope of the resulting curve is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">power</div>", "<div style=\"font-family:Cambria;font-size:17px;\">work</div>", "<div style=\"font-family:Cambria;font-size:17px;\">temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">force</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When the V is plotted against <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">p</span>, the slope  will be  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">slope</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<hr size=\"1\" /><span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">p</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">p</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">v</td></tr></table></div> <br/> recall, the unit of pressure  = NM<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> and volume = M<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> Slope = NM<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> x M<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/>  = NM <br/> note : NM is the unit of work which is also force x displacement </div>", "topic": "WORK, ENERGY AND POWER"}, {"id": "objective>Physics>2006>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The thermometric property of a constant volume thermometer is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">change in pressure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">change in length </div>", "<div style=\"font-family:Cambria;font-size:17px;\">differential expansion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">change in volume </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A constant volume thermometer is a type of gas thermometer. The thermometric property of a gas thermometer is the pressure of the gas. Therefore, the thermometric property of a constant volume thermometer is the change in pressure. So, the correct answer is 'change in pressure'.</div>", "topic": "TEMPERATURE AND ITS MEASUREMENT"}, {"id": "objective>Physics>2006>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">At low humidity in an environment, the human skin is usually </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dry and smooth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">damp and smooth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">damp and rough</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dry and rough</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When humidity is low, the air is dry, meaning there is less moisture in the atmosphere. This can cause the skin to lose moisture, leading to dryness and roughness.</div>", "topic": "VAPOURS : DEW POINT, HUMIDITY AND RELATIVE HUMIDITY"}, {"id": "objective>Physics>2006>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In the diagram above, the pressure of the gas is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">96cm of mercury</div>", "<div style=\"font-family:Cambria;font-size:17px;\">86cm of mercury</div>", "<div style=\"font-family:Cambria;font-size:17px;\">66cm of mercury</div>", "<div style=\"font-family:Cambria;font-size:17px;\">76cm of mercury</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">P = 76 + 10 <br/>  <br/> = 86cmHg. <br/>  <br/> ∴ the pressure of the gas is 86cmHg.</div>", "topic": "PRESSURE : ATMOSPHERIC PRESSURE"}];
